import { Component, Element, Event, EventEmitter, h, Host, Listen, Method, Prop, State, Watch } from '@stencil/core';
import {
  isNullOrUndefined,
  isArrayOfStrings,
  closeAllDropdownsInZG,
  findMatchedItem,
  isNullOrUndefinedOrEmptyString
} from '@src/utils/mx-utils/utils';
import isEmpty from 'lodash.isempty';
import isEqual from 'lodash.isequal';
import { EventTypes, KeyboardCodes } from '@src/utils/mx-utils/Events';
import { CustomKeys, DropdownItem, TreeMenuItem } from '@src/mx-components/menu-item/mx-menu-item/menu-item.interface';
import { getOffset } from '@src/utils/mx-utils/domUtils';
import {
  convertArrayOfStrings, copyUuidFromItemToSelectedItem,
  removeChildInArrayByUuid,
  removeItemsWithEmptyChildrenInPlace
} from '@src/mx-components/menu-item/mx-menu-item/menu-item-utils';
import { setNewUuidsForNestedItems } from '@src/utils/mx-utils/item-uuids';
import { debounce } from '@src/utils/mx-utils';
import itemUtils from '../../../utils/mx-utils/mx-menu-item.utils';
import 'stencil-virtual-scroll';

@Component({
  tag: 'mx-multi-select',
  styleUrl: 'mx-multi-select.css'
})
export class MxMultiSelect {
  @Element() hostEl: HTMLMxMultiSelectElement;

  /** Array of objects or strings that represent items for the user to select.
   *  Objects must have a label, value and selected for example: {label: 'Carrot', value: 'carrot', selected: false}. */
  @Prop({ mutable: true }) items: TreeMenuItem[] | string[] = [];

  /** The item list that sets the default selections, should be subset of items. */
  @Prop({ mutable: true }) selectedItems: TreeMenuItem[] | string[] = [];

  /** If true and there is only one item selected show selected item label instead of '1 item selected' */
  @Prop() readonly showSelectedLabel: boolean = false;

  @Watch('selectedItems')
  handleSelectedItemsChange(newValue: TreeMenuItem[] | string[]) {
    if (this.isFinishedLoading) {
      this._setSelectedItems(newValue);
      this.selectionChanged.emit(newValue);
    }
  }

  /** The visible label text for the dropdown. */
  @Prop() readonly label: string;
  /** The id used for the label attr. for and input attr.id. */
  @Prop() readonly inputId: string;
  /** Disables the dropdown menu, set to false by default. */
  @Prop() readonly isDisabled: boolean;
  /** Allows for setting the optional text displayed. */
  @Prop() readonly optionalText: string;
  /** Allows for setting the optional text displayed. */
  @Prop() readonly dropdownLinkText: string;
  /** When true, the size of the dropdown input is smaller. Set to false by default. */
  @Prop() readonly isCompact: boolean;
  /** Sets the aria-label. */
  @Prop() readonly ariaLabel: string;
  /** Displays the optionalText next to the label. */
  @Prop() readonly displayOptionalText: boolean = false;
  /** Displays the Dropdown Link next to the label. */
  @Prop() readonly displayDropdownLink: boolean = false;
  /** Sets whether a filter search is visible. */
  @Prop() readonly displayFilterSearch: boolean = false;
  /** Sets the number of keystrokes on which filter search should trigger the search. */
  @Prop() readonly keyStrokes: number = 0;
  /** Sets placeholder content in the filter search to provide additional information. */
  @Prop() readonly filterSearchPlaceholder: string = '';
  /** Provide placeholder text to select list. */
  @Prop() readonly placeHolder: string = 'Select Item(s)';
  /** Sets the style rules. */
  @Prop() readonly styleRules: string;
  /** Sets error class in dropdown. */
  @Prop() readonly hasError: boolean = false;
  /** Sets the width of the container. */
  @Prop() readonly width: string = '100%';
  /** Sets the padding-left property. */
  @Prop() readonly paddingLeft: string = '0';
  /** Returns values ONLY array of select items if true. This option is not applicable if the multi-select is having nested values (parent-child relationship). */
  @Prop({ mutable: true }) emitOnlyValue = false;
  /** Renders a drop-up menu instead of dropdown if the select is less than 220px above viewport bottom. */
  @Prop() readonly enableDropUp: boolean = true;
  /** Overrides the dropdown's bottom position to one of your choosing in px. */
  @Prop() readonly dropdownBottomPosition: number;
  /** Sets checkboxes to Compact KDS checkbox. */
  @Prop() readonly compactCheckbox: boolean = false;
  /** Enables selected tag list. */
  @Prop() readonly enableTagList: boolean = false;
  /** Target dropdown options list to attach the dialog, valid values are "body" or a local ng-template variable of another element. */
  @Prop() readonly appendTo: any;
  /** Sets the width of the list container(left side). */
  @Prop() readonly listWidth: string = '100%';
  /** Sets whether to display an option to clear your selection. */
  @Prop() readonly enableClearSelection: boolean = false;
  /** Sets custom keys. */
  @Prop() readonly customKeys: CustomKeys = { key: '', value: '' };
  // Do not expose. This is used for mx-pick-list
  /** Hides the dropdown section of multi-select. */
  @Prop() readonly hideDropdown: boolean = false;
  /** Sets the element name. Used for integration within query panel. */
  @Prop({ reflect: true, attribute: 'name' }) readonly name: string;
  /** If true 'Select All' will disappear on search */

  /** Enables or disables the virtual scroll functionality to increase performance.
   * Enabling this may cause style issues when font sizes or zoom levels are changed from their defaults.
   * DOES NOT WORK WELL WITH NESTED ITEMS.
   * Disabled by default. */
  @Prop() readonly enableVirtualScroll: boolean = false;

  /** Emits event on dropdown change with selectedItems list. */
  @Event() selectionChanged: EventEmitter;
  /** Emits event whenever input is blurred. */
  @Event() inputBlur: EventEmitter;
  /** Emits event whenever the dropdown is closed. */
  @Event() dropdownClose: EventEmitter<HTMLDivElement>;
  /** Emits event whenever dropdown is opened. */
  @Event() dropdownOpen: EventEmitter<HTMLDivElement>;
  /** Event fired when dropdown is opened after it has been rendered. */
  @Event() dropdownOpenRendered: EventEmitter<HTMLDivElement>;
  /** Event fired when dropdown is closed after it has been rendered. */
  @Event() dropdownCloseRendered: EventEmitter<HTMLDivElement>;
  /** Event fired when optional link is clicked. */
  @Event() dropdownLinkClick: EventEmitter;

  @State() isOpen = false;
  @State() searchText = '';
  @State() selectedLabel: string;
  @State() formattedSelectedItems: TreeMenuItem[];
  @State() initInputWithFocus = false;
  @State() filteredData: TreeMenuItem[] = [];
  @State() tagItemWidth: number | null = null;

  private searchInputElement: HTMLMxSearchInputElement;
  private tagsWrapperElement: HTMLDivElement;

  //These variables are set to track  isOpen state and fired the dropdownOpenRendered to recalculate the dropdown height
  private shouldFireOpenRendered: boolean;
  private tagListHeight: number;
  private shouldFireCloseRendered: boolean;
  private tagRemoval = false;
  private spaceBelow = 500;
  private listContainer: HTMLDivElement;
  private allRetrievedSelectedItems: TreeMenuItem[] | string[] = [];
  private isFinishedLoading = false;

  @Watch('isOpen')
  //watching this isOpen to set the shouldFireOpenRendered = true so that we can re-calculate
  //the height after listening to dropdownOpenRendered so that dropdown list is visible without scrolling in section-accordion
  checkIsOpen(newOpen: boolean, prevOpen: boolean) {
    if (newOpen === true && prevOpen === false) {
      this.shouldFireOpenRendered = true;
    } else if (newOpen === false && prevOpen === true) {
      this.shouldFireCloseRendered = true;
    }
  }

  componentShouldUpdate() {
    if (isArrayOfStrings(this.items)) {
      this.items = convertArrayOfStrings(this.items as []);
      setNewUuidsForNestedItems(this.items, 'children');
      return false;
    }
    return true;
  }

  @Watch('items')
  handleItemsChange(newValue: TreeMenuItem[] | string[]) {
    let shouldCallFilterChange = true;
    if (newValue.length === 0) {
      this.filteredData = [];
    }
    if (isArrayOfStrings(newValue)) {
      shouldCallFilterChange = false;
      this.emitOnlyValue = true;
    }
    if (newValue.length > 0 && isArrayOfStrings(newValue) && isNullOrUndefined((newValue[0] as TreeMenuItem).label)) {
      this.emitOnlyValue = true;
    }
    setNewUuidsForNestedItems(this.items, 'children');
    shouldCallFilterChange && this.handleFilterChange(null);
    if (this.enableTagList) {
      this.tagListHeight = this.getTagListHeight();
    }
  }

  @Watch('placeHolder')
  handlePlaceholderChange() {
    this.selectedLabel = this.getDropdownLabel(this.allRetrievedSelectedItems);
  }

  @Listen('click', { target: 'document' })
  docClick(event: MouseEvent) {
    const target: HTMLElement = event.target as HTMLElement;
    if (this.isOpen) {
      const outsideClick: boolean = this.isNotListContainer(target);
      if (outsideClick && this.tagRemoval && target.className === 'clear-link') {
        this.tagRemoval = false;
      }
      if (outsideClick || this.isDropdownLabel(target)) {
        this.closeDropdown();
      }
    }
  }

  @Listen('keydown', { target: 'document' })
  spacebarKey(event: KeyboardEvent) {
    if (event.code === 'Escape') {
      this.closeDropdown();
    }
    if (event.code === 'Space' && (event.target as HTMLElement).classList.value.includes('mx-dropdown-input-wrapper')) {
      return false;
    }
  }

  @Listen('focus', { target: 'document' })
  focusHandler() {
    const inputComponent: HTMLElement = this.hostEl.querySelector('.mx-dropdown-input-wrapper');
    inputComponent.focus();
  }

  @Listen('resize', { target: 'window' })
  handleResize() {
    this.tagItemWidth = this.getTagItemWidth();
  }

  componentWillLoad() {
    if (isArrayOfStrings(this.items)) {
      this.items = convertArrayOfStrings(this.items as string[]);
      this.emitOnlyValue = true;
    }

    if (!this.emitOnlyValue && isArrayOfStrings(this.selectedItems)) {
      this.selectedItems = convertArrayOfStrings(this.selectedItems as string[]);
    }
    if (this.items.length > 0 && this.customKeys && !isEmpty(this.customKeys.key)) {
      this.items = this.formatForCustomKeys(this.items);
    }

    setNewUuidsForNestedItems(this.items, 'children');

    if (!isArrayOfStrings(this.selectedItems) && !isNullOrUndefinedOrEmptyString(this.selectedItems)) {
      this.selectedItems = copyUuidFromItemToSelectedItem(this.selectedItems  as TreeMenuItem[],
                                                          this.items  as TreeMenuItem[]);
    }

    this.handleFilterChange(null);
    if (this.enableTagList) {
      this.tagListHeight = this.getTagListHeight();
    }

    if (this.emitOnlyValue) {
      this.selectedItems = this.getValuesFromObject(this.selectedItems);
    }
    this.formattedSelectedItems = this.formatSelectedItemsToObject(this.selectedItems as TreeMenuItem[]);
    this.updateAllRetrievedSelectedItems(this.selectedItems);
    this.selectedLabel = this.getDropdownLabel(this.allRetrievedSelectedItems);
  }

  componentDidLoad() {
    this.isFinishedLoading = true;
  }

  componentDidUpdate() {
    this.shouldFireOpenRendered && this.dropdownOpenRendered.emit();
    this.shouldFireCloseRendered && this.dropdownCloseRendered.emit();
    this.shouldFireOpenRendered = false;
    this.shouldFireCloseRendered = false;

    if (this.initInputWithFocus && !isNullOrUndefined(this.searchInputElement)) {
      this.searchInputElement.setFocus().then(console.debug);
      this.initInputWithFocus = false;
    }
  }

  private readonly isDropdownLabel = (target) => {
    return target && this.hostEl.contains(target) && target.classList.contains('dropdown-label');
  };

  private readonly isNotListContainer = (target) => {
    return target && !this.hostEl.contains(target) && !this.listContainer.contains(target);
  };

  private formatForCustomKeys(items) {
    if (isNullOrUndefined(items)) {
      return;
    }
    const customizedItems: DropdownItem[] = [];
    items.forEach((it) => {
      const customItem: DropdownItem = { label: it[this.customKeys.key], value: it[this.customKeys.value] };
      if (it.children) {
        customItem.children = this.formatForCustomKeys(it.children);
      }
      customizedItems.push(customItem);
    });
    return customizedItems;
  }

  private getTagListHeight() {
    if (isNullOrUndefined(this.filteredData)) {
      return 0;
    }

    const height = itemUtils.calculateListHeight(this.filteredData, this.compactCheckbox ? 32 : 34);
    const selectAllHeight = this.isCompact ? 38 : 40;
    const hrHeight = 2;
    return height + selectAllHeight + hrHeight + 2; // extra 2px for border
  }

  private getSpaceBelowFromViewport() {
    const elementOffset = getOffset(this.hostEl);
    this.spaceBelow = window.innerHeight - elementOffset.bottom;
  }

  private readonly selectItemInMultiSelect = (event: CustomEvent<TreeMenuItem[]>) => {
    const selectedItems = this.emitOnlyValue ? this.getValuesFromObject(event.detail) : event.detail;
    this.selectedItems = !isNullOrUndefined(selectedItems) ? [...selectedItems] : [];
    this.updateSelection();
  };

  private updateAllRetrievedSelectedItems(selectedItems: TreeMenuItem[] | string[]) {
    if (isArrayOfStrings(selectedItems)) {
      this.allRetrievedSelectedItems = selectedItems;
    } else {
      this.allRetrievedSelectedItems = this.getAllSelectedItems(selectedItems);
    }
  }

  private getAllSelectedItems(arrayToSearch: TreeMenuItem[] | string[],
    retrievedItems: TreeMenuItem[] | string[] = []) {
    if (isArrayOfStrings(arrayToSearch)) {
      return arrayToSearch;
    } else {
      arrayToSearch.forEach((item) => {
        if (isNullOrUndefined(item.children)) {
          retrievedItems.push(item);
        } else {
          this.getAllSelectedItems(item.children, retrievedItems);
        }
      });
    }
    return retrievedItems;
  }

  private updateSelection() {
    this.formattedSelectedItems = this.formatSelectedItemsToObject(this.selectedItems as TreeMenuItem[]);
    this.selectedLabel = this.getDropdownLabel(this.allRetrievedSelectedItems);
  }

  private readonly onTagRemoval = (item) => (_event: CustomEvent) => {
    this.tagRemoval = true;
    this.removeSelectedItem(item);
    this.updateSelection();
    this.formattedSelectedItems = [...this.formatSelectedItemsToObject(this.selectedItems as TreeMenuItem[])];
  };

  private removeSelectedItem(item: string | TreeMenuItem) {
    if ((typeof item === 'string' && isArrayOfStrings(this.selectedItems)) || this.emitOnlyValue) {
      this.selectedItems = (this.selectedItems as string[]).filter((arrayItem) => arrayItem !== item);
    } else {
      removeChildInArrayByUuid(this.selectedItems, (item as TreeMenuItem).uuid);
      this.selectedItems = (this.selectedItems as TreeMenuItem[]).filter((item) => {
        return isNullOrUndefined(item.children) || !isNullOrUndefined(item.children) && item.children.length > 0;
      });
      removeItemsWithEmptyChildrenInPlace(this.selectedItems);
    }
  }

  private getValuesFromObject(items) {
    if (isArrayOfStrings(items)) {
      return items;
    } else {
      const hasChildren = this.hasChildren(items);
      if (hasChildren) {
        return;
      }
      return items.map((item) => item.value);
    }
  }

  private formatSelectedItemsToObject(selectedItems: TreeMenuItem[] | string[]): TreeMenuItem[] {
    if (isNullOrUndefined(selectedItems) || selectedItems.length === 0) {
      return [];
    }

    if (this.hasChildren(selectedItems as TreeMenuItem[]) || !this.emitOnlyValue) {
      return copyUuidFromItemToSelectedItem(selectedItems as TreeMenuItem[], this.items as TreeMenuItem[]);
    }

    if (isArrayOfStrings(selectedItems) || this.emitOnlyValue) {
      return selectedItems.map((selectedItem) => {
        const foundItem = (this.items as TreeMenuItem[]).find((item) => isEqual(item.value, selectedItem));
        const label = isNullOrUndefined(foundItem) ? selectedItem : foundItem.label;
        return { label, value: selectedItem, uuid: foundItem?.uuid } as TreeMenuItem;
      });
    }

    return selectedItems.map((selectedItem) => {
      const foundItem = (this.items as TreeMenuItem[])
        .find((item) => isEqual(item.uuid, selectedItem.uuid));
      return { label: foundItem.label, value: foundItem.value, uuid: foundItem.uuid } as TreeMenuItem;
    });
  }

  private hasChildren(items: TreeMenuItem[]) {
    return items.filter((item) => !isNullOrUndefined(item.children)).length > 0;
  }

  private getDropdownLabel(items: TreeMenuItem[] | string[] = this.formattedSelectedItems): string {
    const SELECT_ONE: string = this.placeHolder;
    const counter: number = items.length || 0;
    if (counter > 1) {
      return `${counter} Items Selected`;
    } else if (counter === 1) {
      if (this.showSelectedLabel) {
        const selItems: TreeMenuItem[] = this.formatSelectedItemsToObject(this.selectedItems);
        return this.getSelectedChildLabel(selItems);
      }
      return '1 Item Selected';
    } else {
      return SELECT_ONE;
    }
  }

  private getSelectedChildLabel(items: TreeMenuItem[]) {
    return items[0].hasOwnProperty('children') && items[0].children.length > 0 ?
      this.getSelectedChildLabel(items[0].children) :
      items[0].label;
  }

  private readonly optionalLinkClickEvent = () => {
    const optionalLinkTextEventDetail = {
      items: this.items,
      selectedItems: this.selectedItems
    };

    this.dropdownLinkClick.emit(optionalLinkTextEventDetail);

    return false;
  }

  private readonly toggleOptionsMenu = (event) => {
    if (!this.isDisabled) {
      const eventCodeOrType = event.code !== undefined ? event.code : event.type;
      switch (eventCodeOrType) {
        case KeyboardCodes.SPACE:
        case KeyboardCodes.ENTER:
        case KeyboardCodes.NUMPAD_ENTER:
        case EventTypes.CLICK:
          this.actionToPerformOnToggle();
          break;
        case KeyboardCodes.ESCAPE:
          this.closeDropdown();
          break;
      }
    }
  };

  private async actionToPerformOnToggle() {
    this.getSpaceBelowFromViewport();
    if (this.isOpen) {
      this.closeDropdown();
      return;
    }
    // If this is used inside ZingGrid, we need to close all other dropdowns before opening this one.
    await closeAllDropdownsInZG(this.hostEl);
    this.isOpen = !this.isOpen;
    if (this.isOpen) {
      if (this.appendTo) {
        this.setListOverlay();
      }
      this.dropdownOpen.emit(this.listContainer);
      this.handleFilterChange(null);
      this.initInputWithFocus = true;
    }
  }

  private setListOverlay() {
    if (!isNullOrUndefined(this.appendTo)) {
      if (this.appendTo === 'body') {
        document.body.appendChild(this.listContainer);
      } else {
        this.appendTo.appendChild(this.listContainer);
      }
    }
  }

  private readonly handleFilterChange = (event: CustomEvent) => {
    if (!this.shouldFilterItems()) {
      return;
    }

    if (event && !isNullOrUndefined(event.detail)) {
      this.searchText = event.detail.searchText;
    }

    this.filteredData = this.items.map((item: TreeMenuItem | string) => findMatchedItem(item, this.searchText))
      .filter((result) => result !== null);
  };

  private readonly shouldFilterItems = (): boolean => {
    return !isNullOrUndefined(this.items) && this.items.length > 0 && this.hasKeyStrokeLength();
  };

  private readonly hasKeyStrokeLength = (): boolean => {
    return this.searchText.length >= this.keyStrokes;
  };

  private readonly clearSelection = (event: MouseEvent) => {
    event.preventDefault();
    event.stopPropagation();
    if (this.isDisabled) {
      return;
    }
    this.selectedItems = [];
    this.updateSelection();
  };

  private closeDropdown() {
    this.isOpen = false;
    this.searchText = '';
    this.dropdownClose.emit(this.listContainer);
  }

  private readonly isOpenTagList = () => {
    return this.isOpen && this.enableTagList && this.selectedItems !== undefined && this.selectedItems?.length > 0;
  }

  private readonly getTagItemWidth = () => {
    // We need to calculate the width of what the tag should be based on the available width in the container.
    // The container has 10 pixels of horizontal padding and a 1 pixel border on the right that need to be removed to account for available space.
    // The tags themselves have a 1 pixel border on the left and right, so we need to remove 2 pixels from the width of each tag.
    const TAG_CONTAINER_SPACING = 13;
    const TAGS_PER_ROW = 2;
    if(this.tagsWrapperElement) {
      return (this.tagsWrapperElement.clientWidth - TAG_CONTAINER_SPACING) / TAGS_PER_ROW ;
    } else {
      const componentWrapper = this.hostEl.querySelector('.mx-dropdown-wrapper');
      return (componentWrapper.clientWidth - TAG_CONTAINER_SPACING) / TAGS_PER_ROW;
    }
  };

  private readonly renderTag = (selectedItem, width) => {
    if (this.emitOnlyValue) {
      const item = this.formatSelectedItemsToObject([selectedItem])[0];
      return <span class='selected-tag-wrapper' style={{ width }}>
        <kds-tag
          style={{ width: '100%' }}
          class='selected-tag flex justify-between'
          kind='action'
          dismissable={true}
          removeSelf={false}
          onClick={(e) => e.preventDefault()}
          onTagRemoved={this.onTagRemoval(item.value)}>
          <span title={item.label}>{item.label}</span>
        </kds-tag>
      </span>;
    }
    return <span class='selected-tag-wrapper' style={{ width }}>
      <kds-tag
        style={{ width: '100%' }}
        class='selected-tag flex justify-between'
        kind='action'
        dismissable={true}
        removeSelf={false}
        onClick={(e) => e.preventDefault()}
        onTagRemoved={this.onTagRemoval(selectedItem)}>
        <span title={selectedItem?.label}>{selectedItem?.label}</span>
      </kds-tag>
    </span>;
  }

  private readonly _setSelectedItems = (newValue: TreeMenuItem[] | string[]) => {
    this.updateAllRetrievedSelectedItems(newValue);
    this.selectedLabel = this.getDropdownLabel(this.allRetrievedSelectedItems);
    this.formattedSelectedItems = this.formatSelectedItemsToObject(newValue);
  }

  /** Toggles the opened status of the dropdown. Optionally, you may pass in a value to show it or hide it.*/
  @Method()
  async toggleDropdown(toggle?: boolean) {
    if (!isNullOrUndefined(toggle)) {
      this.isOpen = toggle;
    } else {
      this.isOpen = !this.isOpen;
    }
  }

  /** Updates Multi-Select's selected items without triggering a selectionChanged event.  */
  @Method()
  async setSelectedItems(newValue: TreeMenuItem[] | string[]) {
    this._setSelectedItems(newValue);
  }

  private updateDisplayChildren(items: TreeMenuItem[], changedItem: TreeMenuItem, displayChildren: boolean) {
    if (items != null && items.length > 0) {
      items.forEach((item: TreeMenuItem) => {
        if (isEqual(item.uuid, changedItem.uuid)) {
          item.displayChildren = displayChildren;
        } else {
          if (item.children) {
            this.updateDisplayChildren(item.children, changedItem, displayChildren);
          }
        }
      });
    }
  }

  render() {
    return (
      <Host>
        <div class='mx-dropdown-wrapper' style={{ width: this.width }}>
          <div class='mx-dropdown-Label-wrapper' style={{ width: this.width }}>
            { this.label && this.label?.length > 0 && (
              <kds-label
                labelClass={ 'mx-label dropdown-label' + (this.hasError ? ' text-negative-less-prominent' : '') }
                inner-htmlFor={this.inputId}>
                <span title={ this.label } class={{ 'label-text': true }}>{ this.label }</span>
                {this.displayOptionalText && (
                  <span class={{
                    'optional-text': true,
                    'text-secondary': !this.hasError,
                    'text-negative-less-prominent': this.hasError
                  }} title={this.optionalText?.length > 1 ? this.optionalText : 'Optional'}>
                    {this.optionalText?.length > 1 ? <span>({this.optionalText})</span> : '(Optional)'}
                  </span>
                )}
              </kds-label>
            )}

            {this.displayDropdownLink && (
              <kds-link
                class='dropdown-optional-link'
                href='javascript:void(0);'
                size={'s'}
                onClick={this.optionalLinkClickEvent}>
                {this.dropdownLinkText}
              </kds-link>
            )}
          </div>
          <div
            class={{
              'mx-dropdown-input-wrapper': true,
              'border-negative-less-prominent': this.hasError,
              'text-secondary': this.isDisabled,
              disabled: this.isDisabled,
              'bg-quaternary-fill': this.isDisabled,
              compact: this.isCompact,
              open: this.isOpen
            }}
            onClick={this.toggleOptionsMenu}
            onKeyUp={this.toggleOptionsMenu}
            title={this.selectedLabel?.length > 0 ? this.selectedLabel : this.placeHolder}
            aria-label={this.label?.length > 0 ? this.label : this.ariaLabel}
            tabindex={this.isDisabled ? -1 : 0}>
            <span
              class={{
                'mx-dropdown-label': true,
                disabled: this.isDisabled,
                open: this.isOpen
              }}
              style={{ paddingLeft: this.paddingLeft }}>
              {this.selectedLabel?.length > 0 ? this.selectedLabel : this.placeHolder}
            </span>
            {this.enableClearSelection && (
              <kds-icon-close
                size='s'
                class='mx-dropdown-icon'
                tabindex='0'
                onClick={this.clearSelection}></kds-icon-close>
            )}
            <kds-icon-chevron-down
              class={{
                'mx-dropdown-icon': true,
                disabled: this.isDisabled,
                open: this.isOpen
              }}
              size='m'></kds-icon-chevron-down>
          </div>

          <div
            style={{ display: this.isOpen && !isNullOrUndefined(this.items) ? 'block' : 'none' }}
            ref={(el: HTMLDivElement) => (this.listContainer = el)}>
            <div
              class={{
                'multi-select-mx-dropdown-list': true,
                'drop-up': this.enableDropUp && this.spaceBelow <= 220,
                'is-compact': this.isCompact,
                'open-tag-list': this.isOpenTagList(),
                'has-search': this.displayFilterSearch
              }}
              style={{
                width: this.listWidth,
                bottom: `${this.dropdownBottomPosition - 1}px`
              }}>

              {this.displayFilterSearch &&
                <mx-search-input
                  ref={(ref) => this.searchInputElement = ref}
                  class='filter-search'
                  keyStrokes={this.keyStrokes}
                  placeholder={this.filterSearchPlaceholder}
                  onFocusout={this.inputBlur.emit}
                  onInputChanged={debounce(this.handleFilterChange, 700)}
                  value={this.searchText}
                  is-compact={this.isCompact} />
              }

              {/* The virtual-scroll components can have visual issues when container sizes are not rounded pixel values. */}
              <div style={{ width: 'round(up, 100%, 1px)', marginTop: '-1px' }}>
                <mx-multi-select-list
                  class='mx-multi-select-list'
                  selectedItems={this.formattedSelectedItems}
                  items={this.filteredData}
                  compactCheckbox={this.compactCheckbox}
                  enableVirtualScroll={this.enableVirtualScroll}
                  onMenuItemOpened={(event) => {
                    this.updateDisplayChildren(
                      this.items as TreeMenuItem[],
                      event.detail,
                      true);
                    this.updateDisplayChildren(
                      this.filteredData as TreeMenuItem[],
                      event.detail,
                      true);
                  }}
                  onMenuItemClosed={(event) => {
                    this.updateDisplayChildren(
                      this.items as TreeMenuItem[],
                      event.detail,
                      false);
                    this.updateDisplayChildren(
                      this.filteredData as TreeMenuItem[],
                      event.detail,
                      false);
                  }}
                  onItemSelected={this.selectItemInMultiSelect} />
              </div>
            </div>

            {this.enableTagList && this.isOpen && this.selectedItems !== undefined && this.selectedItems.length > 0 && (
              <div
                class={{
                  'mx-dropdown-tags-wrapper': true,
                  'is-compact': this.isCompact,
                  'no-search': !this.displayFilterSearch,
                  'drop-up': this.enableDropUp && this.spaceBelow <= 220
                }}
                ref={(el: HTMLDivElement) => (this.tagsWrapperElement = el)}
                // The virtual-scroll components can have visual issues when container sizes are not rounded pixel values.
                style={{
                  width: `round(up, ${this.width}, 1px)`,
                  left: this.width,
                  height: this.tagListHeight + 'px',
                  // this bottom is a bottom of the input, so we need to subtract the height of the tag list to position it correctly
                  // also 1px is added as item list has margin top -1px
                  bottom: `${ (this.dropdownBottomPosition || 0) - (this.tagListHeight) + 1 }px`
                }}>
                <div class='tag-summary'>
                  <span class='truncate' title={this.selectedLabel}>{this.selectedLabel}</span>
                  <kds-link
                    onClick={this.clearSelection}
                    size='m'
                    class='float-right clear-link'
                    tabindex='0'>Clear All
                  </kds-link>
                </div>
                <div class='mx-dropdown-tags-container'>
                  {
                    !this.enableVirtualScroll ?
                      this.allRetrievedSelectedItems?.map((item) => this.renderTag(item, '50%')) :
                      (<virtual-scroll
                        itemCount={this.allRetrievedSelectedItems.length}
                        renderItem={(i) => this.renderTag(this.allRetrievedSelectedItems[i], '100%')}
                        // Floor the tag item width to ensure that the tags fit within the container and prevent visual issues.
                        itemWidth={Math.floor(this.getTagItemWidth())}
                        itemHeight={this.compactCheckbox ? 32 : 34}
                        style={{
                          display: 'flex',
                          width: '100%',
                          height: this.tagListHeight + 'px',
                          'overflow-x': 'hidden',
                          'overflow-y': 'auto'
                        }}
                      />)
                  }
                </div>
              </div>
            )}
          </div>
        </div>
      </Host>
    );
  }
}
